import{_ as t,c as e,o as r,an as i}from"./chunks/framework.DGeO1w4S.js";const g=JSON.parse('{"title":"更新&新闻","description":"ETS2LA 更新与新闻","frontmatter":{"title":"更新&新闻","description":"ETS2LA 更新与新闻","layout":"doc","sidebar":true},"headers":[],"relativePath":"updates/index.md","filePath":"updates/index.md"}'),s={name:"updates/index.md"};function l(n,a,o,p,d,c){return r(),e("div",null,[...a[0]||(a[0]=[i('<h1 id="更新-新闻" tabindex="-1">更新&amp;新闻 <a class="header-anchor" href="#更新-新闻" aria-label="Permalink to “更新&amp;新闻”">​</a></h1><p>这里会发布 ETS2LA 的更新日志与相关通知。</p><h2 id="开发日志" tabindex="-1">开发日志 <a class="header-anchor" href="#开发日志" aria-label="Permalink to “开发日志”">​</a></h2><div class="devblog-list"><h3 id="ets2la-c-四月开发日志" tabindex="-1"><a href="./2026-4-22-april-cs-update.html">ETS2LA C# 四月开发日志</a> <a class="header-anchor" href="#ets2la-c-四月开发日志" aria-label="Permalink to “ETS2LA C# 四月开发日志”">​</a></h3><p><strong>日期：</strong> 2026年4月22日 | <strong>作者：</strong> Tumppi066 | <strong>翻译:</strong> 晚安</p><p>本月我们在自动驾驶实际应用方面取得了一些进展。我们目前有一个非常初级的车道辅助插件概念验证。同时我们也介绍了新的控制方案和 HUD 灵感来源。</p><p><strong>核心亮点：</strong></p><ul><li>🚗 初步 LKAS 插件概念验证已实现，使用 TruckLib 读取游戏数据</li><li>🎮 新控制方案 <code>ApplicationState</code> 带来一致的控制体验</li><li>🖥️ 灵感来源：XPeng 和大众的 HUD 设计</li><li>⚠️ 由于大学事务，进度延误约一个半月</li></ul><p><a href="./2026-4-22-april-cs-update.html"><strong>阅读完整日志</strong> →</a></p><h3 id="ets2la-c-三月开发日志" tabindex="-1"><a href="./2026-3-22-march-cs-update.html">ETS2LA C# 三月开发日志</a> <a class="header-anchor" href="#ets2la-c-三月开发日志" aria-label="Permalink to “ETS2LA C# 三月开发日志”">​</a></h3><p><strong>日期：</strong> 2026年3月22日 | <strong>作者：</strong> Tumppi066 | <strong>翻译:</strong> 晚安</p><p>上个月很大一部分时间我都在忙大学的事情。虽然时间很紧，我们还是在一个大型功能上取得了进展。这一期我们会讲 ETS2LA C# 的发布计划、Linux 原生支持、以及关于项目资金和开源的重要公告。</p><p><strong>核心亮点：</strong></p><ul><li>📅 发布计划：仍计划在今年上半年发布 ETS2LA C#</li><li>🐧 <strong>ETS2LA C# 将原生支持 Linux</strong>，并能有望在 Steam Deck 上运行</li><li>💳 将在 C# 版本中引入可选订阅（基础功能完全免费）</li><li>🔒 驾驶插件将转为限制开源，防止 AI 恶意利用</li></ul><p><a href="./2026-3-22-march-cs-update.html"><strong>阅读完整日志</strong> →</a></p></div>',4)])])}const m=t(s,[["render",l]]);export{g as __pageData,m as default};
